def grade_from_score(s: Int) -> Int:
    if s >= 90:
        return 4
    elif s >= 80:
        return 3
    elif s >= 70:
        return 2
    elif s >= 60:
        return 1
    else:
        return 0

def triangle_type(a: Int, b: Int, c: Int) -> Int:
    if a + b <= c or a + c <= b or b + c <= a:
        return -1
    if a == b and b == c:
        return 3
    if a == b or b == c or a == c:
        return 2
    return 1

def quadrant_of_point(x: Int, y: Int) -> Int:
    if x == 0 or y == 0:
        return 0
    if x > 0 and y > 0:
        return 1
    if x < 0 and y > 0:
        return 2
    if x < 0 and y < 0:
        return 3
    return 4

def season_from_month(m: Int) -> Int:
    if m == 12 or m == 1 or m == 2:
        return 0
    if m >= 3 and m <= 5:
        return 1
    if m >= 6 and m <= 8:
        return 2
    return 3

def score_to_stars(s: Int) -> Int:
    if s < 0:
        return 0
    if s > 100:
        return 5
    return s // 20 + (1 if s % 20 > 0 else 0)

def water_state_from_temp(t: Int) -> Int:
    if t <= 0:
        return 0
    if t < 100:
        return 1
    return 2

def rps_result(a: Int, b: Int) -> Int:
    if a == b:
        return 0
    if (a == 0 and b == 2) or (a == 1 and b == 0) or (a == 2 and b == 1):
        return 1
    return 2

def ticket_price_by_age(age: Int) -> Int:
    if age < 0:
        return -1
    if age < 5:
        return 0
    if age < 18:
        return 10
    if age < 65:
        return 20
    return 12

def weekday_from_daynum(d: Int) -> Int:
    var r = d % 7
    if r == 0:
        return 6
    return r - 1

def switch_calculator(op: Int, a: Int, b: Int) -> Int:
    if op == 0:
        return a + b
    if op == 1:
        return a - b
    if op == 2:
        return a * b
    if op == 3:
        if b == 0:
            return 0
        return a // b
    return -1

def count_digits_loop(n: Int) -> Int:
    if n == 0:
        return 1
    var m = n
    var c = 0
    while m > 0:
        m //= 10
        c += 1
    return c

def zigzag_sum(n: Int) -> Int:
    var s = 0
    for i in range(1, n + 1):
        if i % 2 == 1:
            s += i
        else:
            s -= i
    return s

def sign_product(a: Int, b: Int, c: Int) -> Int:
    var s = 1
    if a < 0:
        s = -s
    if b < 0:
        s = -s
    if c < 0:
        s = -s
    if a == 0 or b == 0 or c == 0:
        return 0
    return s

def gear_shift_logic(speed: Int) -> Int:
    if speed < 10:
        return 1
    if speed < 25:
        return 2
    if speed < 45:
        return 3
    if speed < 70:
        return 4
    return 5

def fibonacci_loop_capped(n: Int, cap: Int) -> Int:
    var a = 0
    var b = 1
    for i in range(n):
        var t = a + b
        a = b
        b = t
        if a > cap:
            return cap
    return a

def dice_sum_category(a: Int, b: Int) -> Int:
    var s = a + b
    if s == 2 or s == 12:
        return 2
    if s == 7:
        return 1
    return 0

def power_of_two_rec(n: Int) -> Int:
    if n == 1:
        return 1
    if n <= 0 or n % 2 != 0:
        return 0
    return power_of_two_rec(n // 2)

def gcd_subtraction_rec(a: Int, b: Int) -> Int:
    if a == b:
        return a
    if a > b:
        return gcd_subtraction_rec(a - b, b)
    return gcd_subtraction_rec(a, b - a)

def digit_product_rec(n: Int) -> Int:
    if n < 10:
        return n
    return (n % 10) * digit_product_rec(n // 10)

def count_ones_binary_rec(n: Int) -> Int:
    if n == 0:
        return 0
    return (n % 2) + count_ones_binary_rec(n // 2)

def rev_helper(n: Int, acc: Int) -> Int:
    if n == 0:
        return acc
    return rev_helper(n // 10, acc * 10 + n % 10)

def reverse_number_rec(n: Int) -> Int:
    return rev_helper(n, 0)

def is_even_rec(n: Int) -> Int:
    if n == 0:
        return 1
    if n == 1:
        return 0
    return is_even_rec(n - 2)

def multiply_by_addition_rec(a: Int, b: Int) -> Int:
    if b == 0:
        return 0
    return a + multiply_by_addition_rec(a, b - 1)

def nth_triangular_rec(n: Int) -> Int:
    if n <= 0:
        return 0
    return n + nth_triangular_rec(n - 1)

def collatz_depth_rec(n: Int) -> Int:
    if n <= 1:
        return 0
    if n % 2 == 0:
        return 1 + collatz_depth_rec(n // 2)
    return 1 + collatz_depth_rec(3 * n + 1)

def fib_pair_rec(n: Int) -> Int:
    if n == 0:
        return 0
    if n == 1:
        return 1
    return fib_pair_rec(n - 1) + fib_pair_rec(n - 2)
